#!/usr/bin/env node
/**
 * Bundle Ruby files into a TypeScript module
 * Reads framework core (lib/homura.rb) and app routes (app/routes.rb)
 * Generates src/ruby-bundle.ts
 */

import { readFileSync, writeFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const webappRoot = join(__dirname, '..');
const frameworkRoot = join(__dirname, '../../..');

function escapeForTemplate(str) {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$/g, '\\$');
}

function main() {
  // Read framework core from root lib/
  const homuraCore = readFileSync(join(frameworkRoot, 'lib/homura.rb'), 'utf-8');
  // Read app routes from webapp's app/
  const userRoutes = readFileSync(join(webappRoot, 'app/routes.rb'), 'utf-8');

  const output = `// Auto-generated by scripts/bundle-ruby.js
// DO NOT EDIT THIS FILE DIRECTLY - edit lib/homura.rb and app/routes.rb instead

export const HOMURA_CORE = \`${escapeForTemplate(homuraCore)}\`;

export const USER_ROUTES = \`${escapeForTemplate(userRoutes)}\`;
`;

  writeFileSync(join(webappRoot, 'src/ruby-bundle.ts'), output);
  console.log('✅ Generated src/ruby-bundle.ts');
}

main();
